div.script:
window.addEventListener('load', function () {
  var stops = JSON.parse(document.getElementById('pc_tour_data').textContent);
  var extras = JSON.parse(document.getElementById('pc_tour_extras').textContent);
  var transports = JSON.parse(document.getElementById('pc_tour_transports').textContent);
  var byId = {};
  stops.forEach(function (s) { byId[s.id] = s; });
  var extraBy = {};
  extras.forEach(function (e) { extraBy[e.code] = e; });
  var originPoint = null;
  var destinationPoint = null;
  function tourHorses() {
    var v = parseInt(document.getElementById('pc_tour_horses').value, 10);
    if (v >= 1) { return v; }
    return 1;
  }
  var tour = [];
  function mk(tag, cls, text) {
    var e = document.createElement(tag);
    if (cls) { e.className = cls; }
    if (text) { e.textContent = text; }
    return e;
  }
  function sortedTour() {
    return tour.slice().sort(function (a, b) {
      return (a.date > b.date) ? 1 : ((b.date > a.date) ? -1 : 0);
    });
  }

  var map = L.map('pc_tour_map', {scrollWheelZoom: false});
  L.tileLayer('https://tile.openstreetmap.org/{z}/{x}/{y}.png', {
    maxZoom: 18, attribution: 'OpenStreetMap'
  }).addTo(map);
  var icon = L.divIcon({className: 'pc-tour-pin', iconSize: [18, 18],
                        iconAnchor: [9, 18], popupAnchor: [0, -16]});
  var routeLayer = L.layerGroup().addTo(map);
  var roadLayer = L.layerGroup().addTo(map);
  var bounds = [];
  stops.forEach(function (s) {
    var box = mk('div');
    box.style.width = '200px';
    var img = document.createElement('img');
    img.src = s.img;
    img.style.cssText = 'width:100%;height:100px;object-fit:cover;border-radius:6px';
    box.appendChild(img);
    box.appendChild(mk('div', 'fw-bold mt-1', s.name));
    var sub = s.code;
    if (s.capacity) { sub = sub + ' · ' + s.capacity + ' cuadras'; }
    box.appendChild(mk('div', 'small text-muted', sub));
    box.appendChild(mk('div', 'small text-muted', 'Precio según disponibilidad'));
    var btn = mk('button', 'btn btn-primary btn-sm mt-2 w-100', 'Añadir parada');
    btn.addEventListener('click', function () { addStop(s.id); });
    box.appendChild(btn);
    L.marker([s.lat, s.lng], {icon: icon}).addTo(map).bindPopup(box);
    bounds.push([s.lat, s.lng]);
  });
  if (bounds.length) { map.fitBounds(bounds, {padding: [30, 30]}); }

  function renderMap() {
    routeLayer.clearLayers();
    var pts = [];
    sortedTour().forEach(function (st, i) {
      var s = byId[st.tplId];
      var badge = L.divIcon({className: 'pc-tour-pin-num',
                             html: String(i + 1),
                             iconSize: [26, 26], iconAnchor: [13, 13]});
      L.marker([s.lat, s.lng], {icon: badge, zIndexOffset: 1000})
        .addTo(routeLayer);
      pts.push([s.lat, s.lng]);
    });
    if (pts.length > 1) {
      L.polyline(pts, {color: '#1f5430', weight: 3, dashArray: '8 6',
                       opacity: 0.85}).addTo(routeLayer);
    }
  }

  var listEl = document.getElementById('pc_tour_stops');
  function defaultDate(n) {
    var d = new Date(Date.now() + (n + 1) * 86400000);
    return d.toISOString().slice(0, 10);
  }
  function addStop(tplId) {
    tour.push({tplId: tplId, plaza: 'box', date: defaultDate(tour.length),
               nights: 1, horses: tourHorses(), checkin: 'Tarde',
               bedding: 'straw', hay: false, sel: {}});
    render();
    map.closePopup();
  }
  function stopExtras(st) {
    var out = [];
    Object.keys(st.sel).forEach(function (code) {
      if (st.sel[code]) {
        if (extraBy[code]) {
          out.push({code: code, qty: extraQty(extraBy[code], st)});
        }
      }
    });
    if (st.hay) { out.push({code: 'SRV-HENO', qty: st.horses * st.nights}); }
    if (st.bedding === 'shavings') {
      out.push({code: 'SRV-VIRUTA', qty: st.horses * st.nights});
    }
    return out;
  }
  function extraQty(e, st) {
    if (e.pricing === 'per_night') { return st.nights; }
    if (e.pricing === 'per_horse_night') { return st.horses * st.nights; }
    return 1;
  }
  function sel(options, value, onChange) {
    var el = document.createElement('select');
    el.className = 'form-select form-select-sm';
    options.forEach(function (o) {
      var op = document.createElement('option');
      op.value = o[0];
      op.textContent = o[1];
      if (value === o[0]) { op.selected = true; }
      el.appendChild(op);
    });
    el.addEventListener('change', function () { onChange(el.value); render(); });
    return el;
  }
  function render() {
    listEl.textContent = '';
    tour.forEach(function (st, i) {
      var s = byId[st.tplId];
      var row = mk('div', 'pc-tour-row');
      var head = mk('div', 'd-flex justify-content-between align-items-center');
      head.appendChild(mk('div', 'fw-bold small', (i + 1) + '. ' + s.name));
      var del = mk('a', 'text-danger fw-bold text-decoration-none', '✕');
      del.href = '#';
      del.addEventListener('click', function (ev) {
        ev.preventDefault();
        tour.splice(i, 1);
        render();
      });
      head.appendChild(del);
      row.appendChild(head);

      var g1 = mk('div', 'd-flex gap-1 mt-1');
      var date = document.createElement('input');
      date.type = 'date';
      date.value = st.date;
      date.title = 'Llegada';
      date.className = 'form-control form-control-sm';
      date.addEventListener('change', function () { st.date = date.value; render(); });
      g1.appendChild(date);
      g1.appendChild(sel([['Mañana', 'Check-in: mañana'],
                          ['Tarde', 'Check-in: tarde'],
                          ['Noche', 'Check-in: noche']],
                         st.checkin, function (v) { st.checkin = v; }));
      row.appendChild(g1);

      var g2 = mk('div', 'd-flex gap-1 mt-1 align-items-center');
      g2.appendChild(sel([[1, '1 noche'], [2, '2 noches'], [3, '3 noches'],
                          [4, '4 noches'], [5, '5 noches'], [6, '6 noches'],
                          [7, '7 noches']].map(function (o) {
                            return [String(o[0]), o[1]];
                          }),
                         String(st.nights),
                         function (v) { st.nights = parseInt(v, 10); }));
      var horses = document.createElement('input');
      horses.type = 'number';
      horses.min = 1;
      horses.max = 40;
      horses.value = st.horses;
      horses.title = 'Caballos';
      horses.className = 'form-control form-control-sm';
      horses.addEventListener('change', function () {
        st.horses = Math.max(1, parseInt(horses.value, 10) || 1);
        render();
      });
      g2.appendChild(horses);
      g2.appendChild(mk('span', 'small text-muted', 'cab.'));
      row.appendChild(g2);

      var g3 = mk('div', 'd-flex gap-1 mt-1');
      g3.appendChild(sel([['box', 'Box'], ['grass', 'Paddock hierba']],
                         st.plaza, function (v) { st.plaza = v; }));
      g3.appendChild(sel([['straw', 'Cama: paja'],
                          ['shavings', 'Cama: viruta']],
                         st.bedding, function (v) { st.bedding = v; }));
      row.appendChild(g3);

      var hayDiv = mk('div', 'form-check mt-1');
      var hay = document.createElement('input');
      hay.type = 'checkbox';
      hay.className = 'form-check-input';
      hay.checked = st.hay;
      hay.id = 'pc_hay_' + i;
      hay.addEventListener('change', function () { st.hay = hay.checked; render(); });
      var hayLb = mk('label', 'form-check-label', 'Heno');
      hayLb.htmlFor = 'pc_hay_' + i;
      hayDiv.appendChild(hay);
      hayDiv.appendChild(hayLb);
      row.appendChild(hayDiv);

      var det = document.createElement('details');
      det.open = !!st.open;
      det.addEventListener('toggle', function () { st.open = det.open; });
      var sum = document.createElement('summary');
      sum.textContent = 'Servicios extra';
      det.appendChild(sum);
      extras.forEach(function (e) {
        var d = mk('div', 'form-check');
        var cb = document.createElement('input');
        cb.type = 'checkbox';
        cb.className = 'form-check-input';
        cb.checked = !!st.sel[e.code];
        cb.id = 'pc_x_' + i + '_' + e.code;
        cb.addEventListener('change', function () {
          st.sel[e.code] = cb.checked;
          render();
        });
        var lb = mk('label', 'form-check-label', e.name);
        lb.htmlFor = cb.id;
        d.appendChild(cb);
        d.appendChild(lb);
        det.appendChild(d);
      });
      row.appendChild(det);
      listEl.appendChild(row);
    });
    document.getElementById('pc_tour_submit').disabled = (tour.length === 0);
    renderMap();
  }
  render();

  // -- route engine ---------------------------------------------------
  var vehicleSel = document.getElementById('pc_tour_vehicle');
  transports.forEach(function (t) {
    var op = document.createElement('option');
    op.value = String(t.id);
    var label = t.name;
    if (t.vehicle_type) { label = label + ' (' + t.vehicle_type + ')'; }
    op.textContent = label;
    vehicleSel.appendChild(op);
  });

  function setRouteMsg(text) {
    document.getElementById('pc_tour_route_msg').textContent = text || '';
  }

  // Photon (OpenStreetMap) geocoder: free, no key, autocomplete-friendly.
  function photonUrl(query, limit) {
    return 'https://photon.komoot.io/api/?lang=es&limit=' + limit
           + '&q=' + encodeURIComponent(query);
  }
  function featureLabel(f) {
    var p = f.properties || {};
    var parts = [p.name];
    if (p.state) { parts.push(p.state); }
    if (p.country) { parts.push(p.country); }
    return parts.filter(Boolean).join(', ');
  }
  function geocode(query) {
    return fetch(photonUrl(query, 1))
      .then(function (r) { return r.json(); })
      .then(function (data) {
        var feats = (data || {}).features || [];
        if (feats.length === 0) { return null; }
        var c = (feats[0].geometry || {}).coordinates || null;
        if (c === null) { return null; }
        return [c[1], c[0]];
      })
      .catch(function () { return null; });
  }
  function setupAutocomplete(input, assign) {
    input.parentNode.style.position = 'relative';
    var boxEl = mk('div', 'pc-ac-box');
    input.parentNode.appendChild(boxEl);
    var timer = null;
    function close() { boxEl.style.display = 'none'; boxEl.textContent = ''; }
    input.addEventListener('input', function () {
      assign(null);
      var query = input.value.trim();
      if (timer) { window.clearTimeout(timer); }
      if (query.length >= 3) {
        timer = window.setTimeout(function () {
          fetch(photonUrl(query, 6)).then(function (r) { return r.json(); })
            .then(function (data) {
              boxEl.textContent = '';
              var feats = (data || {}).features || [];
              if (feats.length === 0) { close(); return; }
              feats.forEach(function (f) {
                var c = (f.geometry || {}).coordinates || null;
                if (c === null) { return; }
                var label = featureLabel(f);
                var item = mk('div', 'pc-ac-item', label);
                item.addEventListener('mousedown', function (ev) {
                  ev.preventDefault();
                  input.value = label;
                  assign([c[1], c[0]]);
                  close();
                });
                boxEl.appendChild(item);
              });
              boxEl.style.display = 'block';
            }).catch(function () { close(); });
        }, 300);
      } else {
        close();
      }
    });
    input.addEventListener('blur', function () {
      window.setTimeout(close, 200);
    });
  }
  setupAutocomplete(document.getElementById('pc_tour_origin'),
                    function (p) { originPoint = p; });
  setupAutocomplete(document.getElementById('pc_tour_destination'),
                    function (p) { destinationPoint = p; });

  function drawRoad(geometry) {
    roadLayer.clearLayers();
    if (geometry) {
      if (geometry.length > 1) {
        var line = L.polyline(geometry, {color: '#b45309', weight: 5,
                                         opacity: 0.75});
        line.addTo(roadLayer);
        map.fitBounds(line.getBounds(), {padding: [40, 40]});
      }
    }
  }

  function showRouteInfo(route) {
    var info = document.getElementById('pc_tour_route_info');
    if (route) {
      document.getElementById('pc_tour_route_km').textContent =
        String(route.distance_km).replace('.', ',') + ' km';
      var hours = Math.floor(route.duration_h);
      var mins = Math.round((route.duration_h - hours) * 60);
      document.getElementById('pc_tour_route_dur').textContent =
        '≈ ' + hours + ' h ' + mins + ' min de conducción';
      var prov = 'OSRM (gratis)';
      if (route.provider === 'google') { prov = 'Google Maps'; }
      if (route.provider === 'fallback') { prov = 'línea recta (estimación)'; }
      document.getElementById('pc_tour_route_provider').textContent =
        '· ' + prov;
      info.classList.remove('d-none');
    }
  }

  function callRoute(waypoints, transportId) {
    return fetch('/tour/route', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({waypoints: waypoints,
                            transport_config_id: transportId})
    }).then(function (r) { return r.json(); });
  }

  function buildWaypoints() {
    var pts = [originPoint];
    sortedTour().forEach(function (st) {
      var s = byId[st.tplId];
      pts.push([s.lat, s.lng]);
    });
    pts.push(destinationPoint);
    return pts;
  }

  document.getElementById('pc_tour_calc').addEventListener('click', function () {
    setRouteMsg('');
    var btn = document.getElementById('pc_tour_calc');
    btn.disabled = true;
    btn.textContent = 'Calculando…';

    function restore() {
      btn.disabled = false;
      btn.textContent = 'Calcular ruta';
    }
    function ensure(pointVar, inputId) {
      if (pointVar) { return Promise.resolve(pointVar); }
      var value = document.getElementById(inputId).value;
      if (value.length >= 3) { return geocode(value); }
      return Promise.resolve(null);
    }

    ensure(originPoint, 'pc_tour_origin').then(function (origin) {
      originPoint = origin;
      return ensure(destinationPoint, 'pc_tour_destination');
    }).then(function (destination) {
      destinationPoint = destination;
      if (originPoint === null) {
        setRouteMsg('Escribe una ciudad de origen para localizarla.');
        restore();
        return;
      }
      if (destinationPoint === null) {
        setRouteMsg('Escribe una ciudad de destino para localizarla.');
        restore();
        return;
      }
      var transportId = vehicleSel.value;
      fetch('/tour/suggest', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({origin: originPoint,
                              destination: destinationPoint,
                              transport_config_id: transportId})
      }).then(function (r) { return r.json(); }).then(function (data) {
        var suggestions = data.suggestions || [];
        var added = 0;
        suggestions.forEach(function (sug) {
          if (byId[sug.id]) {
            var exists = false;
            tour.forEach(function (st) {
              if (st.tplId === sug.id) { exists = true; }
            });
            if (exists === false) {
              addStop(sug.id);
              added += 1;
            }
          }
        });
        var waypoints = buildWaypoints();
        callRoute(waypoints, transportId).then(function (route) {
          drawRoad(route.geometry);
          showRouteInfo(route);
          if (data.network_insufficient) {
            var faltan = data.required_stops - suggestions.length;
            setRouteMsg('Atención: este trayecto necesita ' + data.required_stops
              + ' parada(s) por descanso, pero faltan ' + faltan
              + ' por cubrir (no hay cuadra propia en esa zona de la ruta).');
          } else if (added === 0) {
            setRouteMsg('Este trayecto no necesita paradas intermedias.');
          } else {
            setRouteMsg(added + ' parada(s) obligatoria(s) añadida(s) a tu tour.');
          }
          restore();
        }).catch(function () {
          setRouteMsg('No se pudo dibujar la ruta, inténtalo de nuevo.');
          restore();
        });
      }).catch(function () {
        setRouteMsg('No se pudo calcular la ruta, inténtalo de nuevo.');
        restore();
      });
    });
  });

  function val(id) { return document.getElementById(id).value; }
  document.getElementById('pc_tour_submit').addEventListener('click', function () {
    var err = document.getElementById('pc_tour_error');
    err.classList.add('d-none');
    var payload = {
      customer: {name: val('pc_tour_name'), email: val('pc_tour_email'),
                 phone: val('pc_tour_phone'), rider: val('pc_tour_rider'),
                 stallion: val('pc_tour_stallion'),
                 payment_pref: val('pc_tour_payment')},
      stops: sortedTour().map(function (st) {
        return {template_id: st.tplId, plaza: st.plaza, date: st.date,
                nights: st.nights, horses: st.horses, checkin: st.checkin,
                extras: stopExtras(st)};
      })
    };
    fetch('/tour/submit', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify(payload)
    }).then(function (r) {
      return r.json().then(function (data) { return {ok: r.ok, data: data}; });
    }).then(function (res) {
      if (res.ok) {
        document.getElementById('pc_tour_order').textContent = res.data.name;
        document.getElementById('pc_tour_done').classList.remove('d-none');
        document.getElementById('pc_tour_form').classList.add('d-none');
      } else {
        err.textContent = res.data.error || 'Error';
        err.classList.remove('d-none');
      }
    }).catch(function () {
      err.textContent = 'Error de red';
      err.classList.remove('d-none');
    });
  });
});
